def {{nama_fungsi}}(endpoint_url, api_key, payload, timeout=60):
    """Generator: yield token teks satu per satu dari stream SSE LLM API.
    payload harus sudah menyertakan 'stream': True.
    """
    body = json.dumps(payload).encode("utf-8")
    req = urllib.request.Request(
        endpoint_url,
        data=body,
        headers={
            "Content-Type": "application/json",
            "Authorization": f"Bearer {api_key}",
            "Accept": "text/event-stream",
        },
        method="POST",
    )
    with urllib.request.urlopen(req, timeout=timeout) as resp:
        for raw_line in resp:
            line = raw_line.decode("utf-8").strip()
            if not line.startswith("data:"):
                continue
            data_str = line[len("data:"):].strip()
            if data_str == "{{done_sentinel}}":
                return
            try:
                chunk = json.loads(data_str)
                token = chunk.get("{{data_key}}", "")
                if token:
                    yield token
            except json.JSONDecodeError:
                continue

def {{nama_fungsi}}(stream_generator, on_token=None):
    """Kumpulkan semua token dari stream_generator menjadi string penuh.
    on_token: callable opsional, dipanggil dengan tiap token (untuk update UI).
    """
    parts = []
    for token in stream_generator:
        parts.append(token)
        if on_token is not None:
            on_token(token)
    return "".join(parts)
